const scene = runtimeScene;
const g = scene.getGame().getVariables();
const im = scene.getGame().getInputManager();
const setTxt = (name, s) => { const o = scene.getObjects(name)[0]; if (o) o.setString(s); };
for (const id of im.getStartedTouchIdentifiers()) {
  const x = im.getTouchX(id), y = im.getTouchY(id);
  const hit = (name) => { const o = scene.getObjects(name)[0]; return o && o.insideObject(x, y); };
  if (hit("BtnLevel")) {
    const cur = g.get("g_level").getAsString() === "easy" ? "hard" : "easy";
    g.get("g_level").setString(cur);
    setTxt("TxtLevel", cur === "easy" ? "難度：簡單（3 洞）" : "難度：困難（5 洞）");
  } else if (hit("BtnTime")) {
    const cyc = {30: 45, 45: 60, 60: 30};
    const t = cyc[g.get("g_time").getAsNumber()] || 45;
    g.get("g_time").setNumber(t);
    setTxt("TxtTime", "時間：" + t + " 秒");
  } else if (hit("BtnSolo")) {
    gdjs.evtTools.runtimeScene.replaceScene(scene, "Solo", true);
  } else if (hit("BtnDuo")) {
    gdjs.evtTools.runtimeScene.replaceScene(scene, "Duo", true);
  }
}

const scene = runtimeScene;
const vars = scene.getVariables();
const FRUITS = ["apple","banana","strawberry","grape","watermelon","pineapple","orange","pear","lemon","cherry","blueberry"];
if (vars.get("Phase").getAsString() === "init") {
  vars.get("Phase").setString("play");
  const level = scene.getGame().getVariables().get("g_level").getAsString();
  const keep = level === "easy" ? 3 : 5;
  for (const h of [...scene.getObjects("Hole")]) {
    if (h.getVariables().get("idx").getAsNumber() >= keep) h.deleteFromScene(scene);
  }
  const POS3 = [[384,320],[896,320],[640,560]];
  const POS5 = [[384,300],[896,300],[256,560],[640,560],[1024,560]];
  const pos = keep === 3 ? POS3 : POS5;
  scene.getObjects("Hole").forEach((h,i)=>{
    if (pos[i]) { h.setX(pos[i][0]-h.getWidth()/2); h.setY(pos[i][1]-h.getHeight()/2); }
  });
  vars.get("NeedRound").setNumber(1);
}
if (vars.get("Phase").getAsString() !== "play") return;
if (vars.get("NeedRound").getAsNumber() === 1) {
  vars.get("NeedRound").setNumber(0);
  for (const f of [...scene.getObjects("Fruit")]) f.deleteFromScene(scene);
  const holes = scene.getObjects("Hole");
  const target = FRUITS[Math.floor(Math.random()*FRUITS.length)];
  vars.get("Target").setString(target);
  const correct = Math.floor(Math.random()*holes.length);
  const distract = FRUITS.filter(n=>n!==target).sort(()=>Math.random()-0.5);
  let di = 0;
  holes.forEach((h,i)=>{
    const f = scene.createObject("Fruit");
    if (!f) return;
    f.setAnimationName(i===correct ? target : distract[di++]);
    const s = h.getWidth()*0.85;
    f.setWidth(s); f.setHeight(s);
    f.setX(h.getX()+(h.getWidth()-s)/2);
    f.setY(h.getY()+h.getHeight()*0.25-s*0.75);
    f.setZOrder(5);
  });
  const t = scene.getObjects("TargetFruit")[0];
  if (t) t.setAnimationName(target);
  const tt = scene.getObjects("TargetTxt")[0];
  if (tt) tt.setString(target.toUpperCase());
}
const im = scene.getGame().getInputManager();
for (const id of im.getStartedTouchIdentifiers()) {
  const x = im.getTouchX(id), y = im.getTouchY(id);
  for (const f of scene.getObjects("Fruit")) {
    if (f.insideObject(x, y)) {
      if (f.getAnimationName() === vars.get("Target").getAsString()) {
        vars.get("Score").setNumber(vars.get("Score").getAsNumber()+1);
        gdjs.evtTools.sound.playSound(scene, "hit.mp3", false, 100, 1);
        vars.get("NeedRound").setNumber(1);
      }
      break;
    }
  }
}

const scene = runtimeScene;
const vars = scene.getVariables();
const FRUITS = ["apple","banana","strawberry","grape","watermelon","pineapple","orange","pear","lemon","cherry","blueberry"];
if (vars.get("Phase").getAsString() === "init") {
  vars.get("Phase").setString("play");
  const level = scene.getGame().getVariables().get("g_level").getAsString();
  const keep = level === "easy" ? 3 : 5;
  for (const h of [...scene.getObjects("Hole")]) {
    if (h.getVariables().get("idx").getAsNumber() >= keep) h.deleteFromScene(scene);
  }
  const XS3 = [320, 640, 960], XS5 = [214, 427, 640, 853, 1066];
  const xs = keep === 3 ? XS3 : XS5;
  for (const h of scene.getObjects("Hole")) {
    const zone = h.getVariables().get("zone").getAsNumber();
    const i = h.getVariables().get("idx").getAsNumber();
    const cy = zone === 1 ? 530 : 190;
    h.setX(xs[i] - h.getWidth()/2); h.setY(cy - h.getHeight()/2);
  }
  vars.get("NeedRound").setNumber(1);
}
if (vars.get("Phase").getAsString() === "end") {
  if (vars.get("EndDone").getAsNumber() === 0) {
    vars.get("EndDone").setNumber(1);
    const s1 = vars.get("Score1").getAsNumber(), s2 = vars.get("Score2").getAsNumber();
    const title = s1 > s2 ? "P1 WINS!" : s2 > s1 ? "P2 WINS!" : "DRAW";
    const rt = scene.getObjects("ResultTitle")[0]; if (rt) rt.setString(title);
    const rs = scene.getObjects("ResultScore")[0]; if (rs) rs.setString("P1 " + s1 + " : " + s2 + " P2");
  }
  return;
}
if (vars.get("NeedRound").getAsNumber() === 1) {
  vars.get("NeedRound").setNumber(0);
  for (const f of [...scene.getObjects("Fruit")]) f.deleteFromScene(scene);
  const target = FRUITS[Math.floor(Math.random()*FRUITS.length)];
  vars.get("Target").setString(target);
  for (const zone of [1, 2]) {
    const holes = scene.getObjects("Hole").filter(h => h.getVariables().get("zone").getAsNumber() === zone);
    const correct = Math.floor(Math.random()*holes.length);
    const distract = FRUITS.filter(n=>n!==target).sort(()=>Math.random()-0.5);
    let di = 0;
    holes.forEach((h,i)=>{
      const f = scene.createObject("Fruit");
      if (!f) return;
      f.setAnimationName(i===correct ? target : distract[di++]);
      const s = h.getWidth()*0.85;
      f.setWidth(s); f.setHeight(s);
      f.setX(h.getX()+(h.getWidth()-s)/2);
      if (zone === 1) {
        f.setY(h.getY()+h.getHeight()*0.25-s*0.75);
      } else {
        f.setAngle(180);
        f.setY(h.getY()+h.getHeight()*0.75-s*0.25);
      }
      f.setZOrder(5);
    });
  }
  for (const t of scene.getObjects("TargetFruit")) t.setAnimationName(target);
  const up = target.toUpperCase();
  for (const n of ["Target1Txt","Target2Txt"]) {
    const o = scene.getObjects(n)[0]; if (o) o.setString(up);
  }
}
const im = scene.getGame().getInputManager();
for (const id of im.getStartedTouchIdentifiers()) {
  const wx = im.getTouchX(id), wy = im.getTouchY(id);
  const zone = wy < 360 ? 2 : 1;
  for (const f of scene.getObjects("Fruit")) {
    const fzone = f.getY() < 360 ? 2 : 1;
    if (fzone !== zone) continue;
    if (f.insideObject(wx, wy)) {
      if (f.getAnimationName() === vars.get("Target").getAsString()) {
        const key = zone === 1 ? "Score1" : "Score2";
        vars.get(key).setNumber(vars.get(key).getAsNumber()+1);
        gdjs.evtTools.sound.playSound(scene, "hit.mp3", false, 100, 1);
        vars.get("NeedRound").setNumber(1);
      }
      break;
    }
  }
}
